SELECT [Sales Price Model Item].[Model Item No_], [Item].[Product Family], [Item].[Product Sex], [Sales Price Model Item].[Variable Group 02], Min([Sales Price Model Item].[Variable Code 02]) AS FromSize, Max([Sales Price Model Item].[Variable Code 02]) AS ToSize, Val([Sales Price Model Item].[Unit Price]) AS SalesPrice, [Item].[Trademark Code], [Item].Description, [Sales Price Model Item].[Variable Group 01], [Sales Price Model Item].[Variable Code 01], [Variable Code].Description, [Item].[Line Code], [Sales Price Model Item].[Sales Code], Str(Min(Val([Sales Price Model Item].[variable code 02]))) & "-" & Str(Max(Val([Sales Price Model Item].[variable code 02]))) AS SizeRange
FROM Item INNER JOIN ([Sales Price Model Item] INNER JOIN [Variable Code] ON ([Sales Price Model Item].[Variable Code 01] = [Variable Code].[Variable Code]) AND ([Sales Price Model Item].[Variable Group 01] = [Variable Code].[Variable Group])) ON [Item].No_ = [Sales Price Model Item].[Model Item No_]
GROUP BY [Sales Price Model Item].[Model Item No_], [Item].[Product Family], [Item].[Product Sex], [Sales Price Model Item].[Variable Group 02], Val([Sales Price Model Item].[Unit Price]), [Item].[Trademark Code], [Item].Description, [Sales Price Model Item].[Variable Group 01], [Sales Price Model Item].[Variable Code 01], [Variable Code].Description, [Item].[Line Code], [Sales Price Model Item].[Sales Code]
HAVING ((([Sales Price Model Item].[Variable Group 02])<>"") AND (([Item].[Trademark Code])="THK") AND (([Sales Price Model Item].[Sales Code])=[listino]));

